    case limit
}

enum OrderStatus: String, Codable {
    case pending
    case executed
    case failed
    case cancelled
}

struct Quote: Codable, Identifiable, Hashable {
    let id = UUID()
    let symbol: String
    let price: Double
    let change: Double
    let changePercent: Double
    let updatedAt: Date
}

struct TradeOrder: Codable, Identifiable, Hashable {
    let id: UUID
    let symbol: String
    let side: TradeSide
    let orderType: OrderType
    let quantity: Int
    let limitPrice: Double?
    let submittedAt: Date
    var status: OrderStatus
    var executedPrice: Double?
    var message: String?
    
    init(id: UUID = UUID(), symbol: String, side: TradeSide, orderType: OrderType, quantity: Int, limitPrice: Double? = nil, submittedAt: Date = Date(), status: OrderStatus = .pending, executedPrice: Double? = nil, message: String? = nil) {
        self.id = id
        self.symbol = symbol
        self.side = side
        self.orderType = orderType
        self.quantity = quantity
        self.limitPrice = limitPrice
        self.submittedAt = submittedAt
        self.status = status
        self.executedPrice = executedPrice
        self.message = message
    }
}

struct Holding: Codable, Identifiable, Hashable {
    let id = UUID()
    let symbol: String
    var quantity: Int
    var averageCost: Double
    var marketPrice: Double
    
    var marketValue: Double { Double(quantity) * marketPrice }
    var costBasis: Double { Double(quantity) * averageCost }
    var unrealizedPnL: Double { marketValue - costBasis }
    var unrealizedPnLPercent: Double { costBasis == 0 ? 0 : (unrealizedPnL / costBasis) * 100 }
}

struct Portfolio: Codable, Hashable {
    var cash: Double
    var holdings: [Holding]
    
    var totalMarketValue: Double {
        holdings.reduce(0) { $0 + $1.marketValue } + cash
    }
    
    var totalCostBasis: Double {
        holdings.reduce(0) { $0 + $1.costBasis } + cash
    }
    
    var totalPnL: Double {
        totalMarketValue - totalCostBasis
    }
}

struct WatchlistItem: Codable, Identifiable, Hashable {
    let id = UUID()
    let symbol: String
    var quote: Quote?
}

struct APIErrorResponse: Codable {
    let message: String
}

