@MainActor
final class TradingViewModel: ObservableObject {
    @Published var portfolio = Portfolio(cash: 25000, holdings: [])
    @Published var quotes: [String: Quote] = [:]
    @Published var watchlist: [WatchlistItem] = [
        .init(symbol: "AAPL"),
        .init(symbol: "MSFT"),
        .init(symbol: "NVDA"),
        .init(symbol: "TSLA"),
        .init(symbol: "AMZN")
    ]
    @Published var orders: [TradeOrder] = []
    @Published var selectedSymbol: String = "AAPL"
    @Published var quantity: String = "1"
    @Published var limitPrice: String = ""
    @Published var orderType: OrderType = .market
    @Published var side: TradeSide = .buy
    @Published var isSubmitting = false
    @Published var errorMessage: String?
    @Published var lastExecutionMessage: String?
    @Published var marketOpen = true
    
    private var quoteTask: Task<Void, Never>?
    
    init() {
        Task {
            await refreshAll()
        }
        startRealtimeQuotes()
    }
    
    deinit {
        quoteTask?.cancel()
    }
    
    func refreshAll() async {
        await loadPortfolio()
        await loadOrders()
        await refreshWatchlistQuotes()
    }
    
    func loadPortfolio() async {
        do {
            portfolio = try await SecureAPIClient.shared.fetchPortfolio()
        } catch {
            portfolio = samplePortfolio()
        }
    }
    
    func loadOrders() async {
        do {
            orders = try await SecureAPIClient.shared.fetchOrders()
        } catch {
            orders = []
        }
    }
    
    func refreshWatchlistQuotes() async {
        await withTaskGroup(of: Quote?.self) { group in
            for item in watchlist {
                group.addTask {
                    do { return try await SecureAPIClient.shared.fetchQuote(symbol: item.symbol) }
                    catch { return self.mockQuote(symbol: item.symbol) }
                }
            }
            
            var updated: [String: Quote] = [:]
            for await quote in group {
                if let quote {
                    updated[quote.symbol] = quote
                }
            }
            quotes = updated
            watchlist = watchlist.map { item in
                var copy = item
                copy.quote = updated[item.symbol]
                return copy
            }
            syncHoldingsMarketPrices()
        }
    }
    
    func startRealtimeQuotes() {
        quoteTask?.cancel()
        quoteTask = Task.detached(priority: .background) { [weak self] in
            while !Task.isCancelled {
                await self?.refreshWatchlistQuotes()
                try? await Task.sleep(nanoseconds: 3_000_000_000)
            }
        }
    }
    
    func submitTrade() async {
        guard let qty = Int(quantity), qty > 0 else {
            errorMessage = "Enter a valid quantity."
            return
        }
        
        let limit: Double?
        if orderType == .limit {
            guard let lp = Double(limitPrice), lp > 0 else {
                errorMessage = "Enter a valid limit price."
                return
            }
            limit = lp
        } else {
            limit = nil
        }
        
        isSubmitting = true
        errorMessage = nil
        defer { isSubmitting = false }
        
        let order = TradeOrder(symbol: selectedSymbol, side: side, orderType: orderType, quantity: qty, limitPrice: limit)
        
        do {
            let result = try await SecureAPIClient.shared.submitOrder(order)
            orders.insert(result, at: 0)
            lastExecutionMessage = "\(result.side.rawValue.capitalized) \(result.quantity) \(result.symbol) \(result.status.rawValue)"
            await refreshAll()
        } catch {
            let fallback = simulateExecution(for: order)
            orders.insert(fallback, at: 0)
            applyFallbackExecution(fallback)
            lastExecutionMessage = fallback.message ?? "Order processed."
        }
    }
    
    private func applyFallbackExecution(_ order: TradeOrder) {
        guard order.status == .executed, let price = order.executedPrice else { return }
        switch order.side {
        case .buy:
            let cost = price * Double(order.quantity)
            guard portfolio.cash >= cost else {
                errorMessage = "Insufficient cash."
                return
            }
            portfolio.cash -= cost
            if let index = portfolio.holdings.firstIndex(where: { $0.symbol == order.symbol }) {
                var holding = portfolio.holdings[index]
                let totalShares = holding.quantity + order.quantity
                holding.averageCost = ((holding.averageCost * Double(holding.quantity)) + cost) / Double(totalShares)
                holding.quantity = totalShares
                holding.marketPrice = price
                portfolio.holdings[index] = holding
            } else {
                portfolio.holdings.append(Holding(symbol: order.symbol, quantity: order.quantity, averageCost: price, marketPrice: price))
            }
        case .sell:
            guard let index = portfolio.holdings.firstIndex(where: { $0.symbol == order.symbol }) else { return }
            var holding = portfolio.holdings[index]
            guard holding.quantity >= order.quantity else { return }
            holding.quantity -= order.quantity
            holding.marketPrice = price
            if holding.quantity == 0 {
                portfolio.holdings.remove(at: index)
            } else {
                portfolio.holdings[index] = holding
            }
            portfolio.cash += price * Double(order.quantity)
        }
        syncHoldingsMarketPrices()
    }
    
    private func syncHoldingsMarketPrices() {
        for index in portfolio.holdings.indices {
            if let quote = quotes[portfolio.holdings[index].symbol] {
                portfolio.holdings[index].marketPrice = quote.price
            }
        }
    }
    
    private func simulateExecution(for order: TradeOrder) -> TradeOrder {
        var result = order
        let price = quotes[order.symbol]?.price ?? Double.random(in: 50...300)
        switch order.orderType {
        case .market:
            result.status = .executed
            result.executedPrice = price
            result.message = "Executed at market price \(price.formattedCurrency)"
        case .limit:
            let limit = order.limitPrice ?? price
            let canExecute = (order.side == .buy) ? price <= limit : price >= limit
            if canExecute {
                result.status = .executed
                result.executedPrice = price
                result.message = "Limit order executed at \(price.formattedCurrency)"
            } else {
                result.status = .pending
                result.message = "Limit order pending."
            }
        }
        return result
    }
    
    private func mockQuote(symbol: String) -> Quote {
        let base = quotes[symbol]?.price ?? Double.random(in: 80...450)
        let movement = Double.random(in: -3.5...3.5)
        let newPrice = max(1, base + movement)
        return Quote(symbol: symbol, price: newPrice, change: movement, changePercent: (movement / max(1, base)) * 100, updatedAt: Date())
    }
    
    private func samplePortfolio() -> Portfolio {
        Portfolio(
            cash: 25000,
            holdings: [
                Holding(symbol: "AAPL", quantity: 40, averageCost: 170, marketPrice: quotes["AAPL"]?.price ?? 172),
                Holding(symbol: "MSFT", quantity: 20, averageCost: 320, marketPrice: quotes["MSFT"]?.price ?? 326)
            ]
        )
    }
}

